mapper.select:
SELECT
id, user_id, book_id, chapter_number, position,
reading_time_seconds, is_completed, last_read_at,
created_at, updated_at
FROM chapter_progress
WHERE user_id = #{userId}
AND book_id = #{bookId}
AND chapter_number = #{chapterNumber}

